  window.EXTRA_READ_STORIES.push(...[{"id":"da-morgen","title":"Morgen i byen","subtitle":"Morning in the city","trail":"green-circle","categoryId":"da","sentences":[{"foreign":"God morgen!","en":"Good morning!"},{"foreign":"Hej. Jeg er lige ankommet.","en":"Hi. I just arrived."},{"foreign":"Det er koldt, men solen skinner.","en":"It's cold, but the sun is shining."},{"foreign":"Jeg tager bycyklen langs gågaden.","en":"I'm taking the city bike along the pedestrian street."},{"foreign":"Undskyld, hvor er stoppestedet for letbanen?","en":"Excuse me, where is the light-rail stop?"},{"foreign":"Ligeud, over fortovet ved vejkrydset.","en":"Straight ahead, across the sidewalk by the intersection."},{"foreign":"Tak. Går der en rute til centrum nu?","en":"Thanks. Is there a route into the center now?"},{"foreign":"Ja. Se på afgangstavlen, eller tag en taxa hvis du har travlt.","en":"Yes. Check the departure board, or take a taxi if you're in a hurry."},{"foreign":"Mange tak. Ha en god dag!","en":"Thank you so much. Have a nice day!"},{"foreign":"Ingen problem. Held og lykke!","en":"No problem. Good luck!"}],"glosses":{"lige":"just (recently)","ankommet":"arrived","skinner":"is shining","bycyklen":"the city bike","gågaden":"the pedestrian street","stoppestedet":"the stop","letbanen":"the light rail","ligeud":"straight ahead","fortovet":"the sidewalk","vejkrydset":"the intersection","rute":"route","centrum":"the center","afgangstavlen":"the departure board","taxa":"taxi","travlt":"in a hurry","held og lykke":"good luck"}},{"id":"da-kaffe","title":"En kaffe, tak","subtitle":"Ordering coffee","trail":"green-circle","categoryId":"da","sentences":[{"foreign":"Hej! Er der ledigt her i caféen?","en":"Hi! Is there a free table here in the café?"},{"foreign":"Ja. Vil du se på menuen?","en":"Yes. Would you like to look at the menu?"},{"foreign":"En kaffe, tak. Uden mælk.","en":"One coffee, please. Without milk."},{"foreign":"Vil du bestille morgenmad også? Vi har te, juice og ostemad.","en":"Would you also like to order breakfast? We have tea, juice, and cheese sandwiches."},{"foreign":"Hvad anbefaler du?","en":"What do you recommend?"},{"foreign":"Vegetarisk suppe er god i dag. Dessert senere hvis du vil.","en":"The vegetarian soup is good today. Dessert later if you want."},{"foreign":"En ostemad, tak. Er den stærk?","en":"A cheese sandwich, please. Is it spicy?"},{"foreign":"Nej, mild. Vi har åbent til tre. Takeaway går fint hvis du har travlt.","en":"No, mild. We're open until three. Takeaway is fine if you're in a hurry."},{"foreign":"Kan jeg få regningen nu? Tips er okay her, ikke?","en":"Can I get the bill now? Tipping is okay here, right?"},{"foreign":"Ja. Det bliver femogfyrre kroner. Ha en god dag!","en":"Yes. That's forty-five kroner. Have a nice day!"}],"glosses":{"ledigt":"free / available","caféen":"the café","menuen":"the menu","uden mælk":"without milk","bestille":"to order","morgenmad":"breakfast","te":"tea","juice":"juice","anbefaler":"recommend","vegetarisk":"vegetarian","ostemad":"cheese sandwich","dessert":"dessert","stærk":"spicy / strong","mild":"mild","takeaway":"takeaway","regningen":"the bill","tips":"tip","femogfyrre":"forty-five","kroner":"kroner"}},{"id":"da-tog","title":"I toget","subtitle":"On the train","trail":"green-circle","categoryId":"da","sentences":[{"foreign":"Går dette tog til København?","en":"Does this train go to Copenhagen?"},{"foreign":"Ja, det passer. Spor fire. Næste afgang om ti minutter.","en":"Yes, that's right. Track four. Next departure in ten minutes."},{"foreign":"Hvor køber jeg billet? Går det an med månedskort?","en":"Where do I buy a ticket? Can I use a monthly pass?"},{"foreign":"I appen eller i billetautomaten. Ellers er enkeltbillet fint.","en":"In the app or at the ticket machine. Otherwise a one-way ticket is fine."},{"foreign":"Enkeltbillet, tak. Vindue, gerne. Hvilken zone er det?","en":"One-way ticket, please. A window seat, if possible. Which zone is it?"},{"foreign":"Zone et til tre. Der er lidt forsinkelse i myldretiden.","en":"Zones one to three. There's a bit of a delay in rush hour."},{"foreign":"Hvor lang tid tager det så? Jeg skal nå et skift.","en":"How long does it take then? I need to make a transfer."},{"foreign":"Cirka to timer. Endestationen er København H.","en":"About two hours. The last stop is Copenhagen Central."},{"foreign":"Fint. Er der parkering ved stationen hvis jeg kommer i bil næste gang?","en":"Good. Is there parking at the station if I come by car next time?"},{"foreign":"Ja, men det koster. Ha en god tur!","en":"Yes, but it costs. Have a nice trip!"}],"glosses":{"passer":"that's right","spor":"track","afgang":"departure","billet":"ticket","månedskort":"monthly pass","billetautomaten":"the ticket machine","enkeltbillet":"one-way ticket","zone":"zone","forsinkelse":"delay","myldretiden":"rush hour","skift":"transfer","cirka":"about","endestationen":"the terminus","parkering":"parking"}},{"id":"da-bibliotek","title":"På biblioteket","subtitle":"At the library","trail":"blue-square","categoryId":"da","sentences":[{"foreign":"Hej, jeg leder efter et stille sted at studere.","en":"Hi, I'm looking for a quiet place to study."},{"foreign":"Ovenpå er der ledige borde ved vinduet. Klasselokalet er optaget, og labben også.","en":"Upstairs there are free tables by the window. The classroom is busy, and the lab too."},{"foreign":"Hvor længe har I åbent?","en":"How late are you open?"},{"foreign":"Til klokken ni i aften. Auditoriet lukker tidligere.","en":"Until nine this evening. The lecture hall closes earlier."},{"foreign":"Kan jeg låne bøger med studiekort? Jeg bor i et kollegium lige ved siden af.","en":"Can I borrow books with a student ID? I live in a dorm nearby."},{"foreign":"Ja. Skal du bruge noget fra pensumlisten til faget?","en":"Yes. Do you need anything from the reading list for your course?"},{"foreign":"Måske senere. Jeg har gruppearbejde med en medstuderende først. Kan du gentage det?","en":"Maybe later. I have group work with a classmate first. Could you repeat that?"},{"foreign":"Husk at tage noter. Kontortid hos underviseren er i morgen. Tilmelding til lab er online.","en":"Remember to take notes. The teacher's office hours are tomorrow. Lab enrollment is online."},{"foreign":"Tak. Jeg håber jeg består eksamen. Specialet kommer senere.","en":"Thanks. I hope I'll pass the exam. The thesis comes later."},{"foreign":"Held og lykke med eksamen næste uge!","en":"Good luck with the exam next week!"}],"glosses":{"stille":"quiet","studere":"to study","ledige":"free","optaget":"busy","labben":"the lab","auditoriet":"the lecture hall","studiekort":"student ID","kollegium":"student housing / dorm","pensumlisten":"the reading list","faget":"the course","gruppearbejde":"group work","medstuderende":"classmate","gentage":"to repeat","noter":"notes","kontortid":"office hours","underviseren":"the teacher","tilmelding":"enrollment","består":"pass","eksamen":"exam","specialet":"the thesis"}},{"id":"da-marked","title":"På markedet","subtitle":"At the market","trail":"blue-square","categoryId":"da","sentences":[{"foreign":"Hej. Er der tilbud i supermarkedet i dag?","en":"Hi. Is there a deal at the supermarket today?"},{"foreign":"Ja, grøntsager er billige. Kylling er nedsat også.","en":"Yes, vegetables are cheap. Chicken is on sale too."},{"foreign":"Hvad koster den ost?","en":"How much is that cheese?"},{"foreign":"Tredive kroner stykket. Skal du have en pose?","en":"Thirty kroner each. Would you like a bag?"},{"foreign":"Ja, gerne. Jeg tager to oste og fire æbler.","en":"Yes, please. I'll take two cheeses and four apples."},{"foreign":"Indkøbsvognen står derovre hvis du skal have mere. Åbningstiderne står på døren.","en":"The shopping cart is over there if you need more. Opening hours are on the door."},{"foreign":"Tak. Kan jeg betale med dankort ved kassen, eller MobilePay?","en":"Thanks. Can I pay with Dankort at the checkout, or MobilePay?"},{"foreign":"Begge dele. Vi er næsten kontantløse. Her er byttepenge hvis du skal bruge dem.","en":"Either. We're almost cashless. Here's change if you need it."},{"foreign":"Super. Jeg leder også efter en gave. Den her trøje er for stor. Har I en anden størrelse?","en":"Great. I'm also looking for a gift. This sweater is too big. Do you have another size?"},{"foreign":"Prøverummet er der. Du kan bytte den senere, eller få pengene tilbage.","en":"The fitting room is there. You can exchange it later, or get a refund."},{"foreign":"Blå er fin. Farvel!","en":"Blue is nice. Bye!"}],"glosses":{"tilbud":"deal / special offer","supermarkedet":"the supermarket","grøntsager":"vegetables","billige":"cheap","kylling":"chicken","nedsat":"on sale","stykket":"each","pose":"bag","indkøbsvognen":"the shopping cart","åbningstiderne":"opening hours","betale":"to pay","dankort":"Danish debit card","kassen":"the checkout","kontantløse":"cashless","byttepenge":"change","gave":"gift","trøje":"sweater","for stor":"too big","størrelse":"size","prøverummet":"the fitting room","bytte":"to exchange","pengene tilbage":"a refund"}},{"id":"da-venner","title":"Nye venner","subtitle":"New friends","trail":"blue-square","categoryId":"da","sentences":[{"foreign":"Hej, jeg hedder Sam.","en":"Hi, my name is Sam."},{"foreign":"Dejligt at se dig. Jeg er Noor.","en":"Nice to see you. I'm Noor."},{"foreign":"Hvor kommer du fra?","en":"Where are you from?"},{"foreign":"Fra Canada, men jeg bor her nu. Og dig?","en":"From Canada, but I live here now. And you?"},{"foreign":"Herfra. Hvad studerer du?","en":"From here. What do you study?"},{"foreign":"Informatik. Har du planer i weekenden?","en":"Computer science. Do you have plans this weekend?"},{"foreign":"Ja, en lille fest hos en kammerat. Er du ledig? Du er inviteret hvis du vil.","en":"Yes, a small party at a buddy's place. Are you free? You're invited if you want."},{"foreign":"Gerne! Jeg kan lide at hænge ud med nye folk. Hobbyen min er fotografi.","en":"I'd love to! I like hanging out with new people. My hobby is photography."},{"foreign":"Mega hyggeligt. Det er hans fødselsdag, så vi siger tillykke, og skål!","en":"Really nice. It's his birthday, so we say happy birthday, and cheers!"},{"foreign":"Kaffe efter forelæsningen i morgen? Eller museum i weekenden?","en":"Coffee after the lecture tomorrow? Or the museum this weekend?"},{"foreign":"Ja. Vi ses snart. Pas på dig, og hold kontakten!","en":"Yes. See you soon. Take care, and stay in touch!"}],"glosses":{"dejligt at se dig":"nice to see you","herfra":"from here","planer":"plans","weekenden":"the weekend","fest":"party","kammerat":"buddy","er du ledig":"are you free","inviteret":"invited","hænge ud":"hang out","hobbyen":"the hobby","fotografi":"photography","hyggeligt":"cozy / nice","fødselsdag":"birthday","tillykke":"congratulations / happy birthday","skål":"cheers","forelæsningen":"the lecture","vi ses snart":"see you soon","pas på dig":"take care","hold kontakten":"stay in touch"}},{"id":"da-job","title":"Første arbejdsdag","subtitle":"First day at work","trail":"black-diamond","categoryId":"da","sentences":[{"foreign":"Velkommen til teamet, Sam. Det her er kontoret.","en":"Welcome to the team, Sam. This is the office."},{"foreign":"Tak. Jeg er lidt nervøs. Er det fuldtid eller deltid?","en":"Thanks. I'm a bit nervous. Is it full-time or part-time?"},{"foreign":"Fuldtid. Efter ansættelsen præsenterer chefen projektet.","en":"Full-time. After the hire, the boss presents the project."},{"foreign":"Hvor kan jeg stille mine ting?","en":"Where can I put my things?"},{"foreign":"Her ved vinduet er dit skrivebord. Adgangskoden får du af en kollega.","en":"Here by the window is your desk. You'll get the password from a coworker."},{"foreign":"Hvis du har spørgsmål, så spørg bare. Dagsordenen ligger i mødelokalet.","en":"If you have questions, just ask. The agenda is in the meeting room."},{"foreign":"Forstået. Hvem er min vejleder i dag?","en":"Understood. Who is my supervisor today?"},{"foreign":"Det er mig. Deadlinen for første faktura til kunden er fredag.","en":"That's me. The deadline for the first invoice to the client is Friday."},{"foreign":"Ok. Hvornår kommer lønnen, og kan jeg have hjemmearbejde nogle dage?","en":"Ok. When does the salary come, and can I work from home some days?"},{"foreign":"Løn den 15. Se lønsedlen. Hjemmearbejde efter prøvetiden.","en":"Salary on the 15th. See the payslip. Remote work after the trial period."},{"foreign":"Flot. Bliver der forretningsrejse senere på året?","en":"Great. Will there be a business trip later in the year?"},{"foreign":"Muligt. Held og lykke!","en":"Possibly. Good luck!"}],"glosses":{"teamet":"the team","kontoret":"the office","nervøs":"nervous","fuldtid":"full-time","deltid":"part-time","ansættelsen":"the hire","chefen":"the boss","projektet":"the project","skrivebord":"desk","adgangskoden":"the password","kollega":"coworker","dagsordenen":"the agenda","mødelokalet":"the meeting room","vejleder":"supervisor","deadlinen":"the deadline","faktura":"invoice","kunden":"the client","lønnen":"the salary","lønsedlen":"the payslip","hjemmearbejde":"remote work","prøvetiden":"the trial period","forretningsrejse":"business trip"}},{"id":"da-laege","title":"Hos lægen","subtitle":"At the doctor's","trail":"black-diamond","categoryId":"da","sentences":[{"foreign":"Goddag. Har du lægetid nu?","en":"Good day. Do you have a doctor's appointment now?"},{"foreign":"Ja. Hvad er der galt?","en":"Yes. What's the matter?"},{"foreign":"Jeg har haft ondt i halsen i to dage, og hovedpine. Smerte i øret også.","en":"I've had a sore throat for two days, and a headache. Pain in the ear too."},{"foreign":"Har du feber, hoste eller andre symptomer?","en":"Do you have a fever, a cough, or other symptoms?"},{"foreign":"Lidt feber i morges, og lidt hoste. Ingen mavepine.","en":"A little fever this morning, and a bit of a cough. No stomachache."},{"foreign":"Sygeplejersken tager blodtryk først. Sig aaa.","en":"The nurse will take blood pressure first. Say ah."},{"foreign":"Det ligner en mild forkølelse. Er du allergisk over for noget?","en":"It looks like a mild cold. Are you allergic to anything?"},{"foreign":"Nej. Skal jeg have recept på medicin?","en":"No. Do I need a prescription for medicine?"},{"foreign":"Ikke endnu. Hvile, vand og paracetamol. Kom igen hvis det bliver værre.","en":"Not yet. Rest, water, and paracetamol. Come back if it gets worse."},{"foreign":"Mange tak. Kan jeg få en sygemelding hvis det bliver værre?","en":"Thank you. Can I get a sick note if it gets worse?"},{"foreign":"Ja. Ved akut nødsituation: ring 112, eller gå på skadestuen.","en":"Yes. In an emergency: call 112, or go to A&E / the ER."}],"glosses":{"lægetid":"doctor's appointment","ondt i halsen":"sore throat","hovedpine":"headache","smerte":"pain","feber":"fever","hoste":"cough","symptomer":"symptoms","mavepine":"stomachache","sygeplejersken":"the nurse","blodtryk":"blood pressure","forkølelse":"cold","allergisk":"allergic","recept":"prescription","medicin":"medicine","paracetamol":"paracetamol","sygemelding":"sick note","nødsituation":"emergency","skadestuen":"the ER / A&E"}},{"id":"da-bolig","title":"Leder efter et værelse","subtitle":"Looking for a room","trail":"black-diamond","categoryId":"da","sentences":[{"foreign":"Hej, jeg ringer om lejligheden på nettet.","en":"Hi, I'm calling about the apartment online."},{"foreign":"Ja, den er stadig ledig. Hvornår vil du se den?","en":"Yes, it's still free. When would you like to see it?"},{"foreign":"I eftermiddag går fint, omkring tre.","en":"This afternoon works fine, around three."},{"foreign":"Fint. Den ligger i kvarteret, tredje sal. Det er et bofællesskab. Du bliver lejer.","en":"Fine. It's in the neighborhood, third floor. It's a shared flat. You'll be a tenant."},{"foreign":"Er der elevator? Jeg har bare en kuffert med tøj. Hotel er for dyrt i længden.","en":"Is there an elevator? I only have a suitcase with clothes. A hotel is too expensive long-term."},{"foreign":"Nej, kun trapper. Soveværelset er lyst, og der er altan.","en":"No, only stairs. The bedroom is bright, and there is a balcony."},{"foreign":"Hvad med stuen og vaskerummet? Nogen lækage i badeværelset?","en":"What about the living room and the laundry room? Any leak in the bathroom?"},{"foreign":"Fælles. Ingen lækage. Huslejen inkluderer internet; fællesudgifter kommer ekstra.","en":"Shared. No leak. The rent includes internet; shared costs come extra."},{"foreign":"Og er der depositum? Hvornår får jeg nøgler?","en":"And is there a deposit? When do I get keys?"},{"foreign":"Ja, en måned. Udlejer møder dig ved postkassen med lejekontrakten.","en":"Yes, one month. The landlord will meet you at the mailbox with the lease."},{"foreign":"Flot. Sig til hvis naboen klager over støj. Jeg er stille.","en":"Great. Let me know if the neighbor complains about noise. I'm quiet."}],"glosses":{"lejligheden":"the apartment","ledig":"available","kvarteret":"the neighborhood","bofællesskab":"shared flat","lejer":"tenant","elevator":"elevator","kuffert":"suitcase","hotel":"hotel","soveværelset":"the bedroom","altan":"balcony","stuen":"the living room","vaskerummet":"the laundry room","lækage":"leak","fælles":"shared","huslejen":"the rent","fællesudgifter":"shared costs","depositum":"deposit","nøgler":"keys","udlejer":"landlord","postkassen":"the mailbox","lejekontrakten":"the lease","naboen":"the neighbor","støj":"noise"}},{"id":"da-nyheder","title":"Strejke i metroen","subtitle":"Subway strike","trail":"double-black-diamond","categoryId":"da","sentences":[{"foreign":"Så du nyheden i morges?","en":"Did you see the news this morning?"},{"foreign":"Nej, hvad er der sket?","en":"No, what happened?"},{"foreign":"I morgen er der strejke i metroen og på flere ruter.","en":"Tomorrow there's a strike on the subway and on several routes."},{"foreign":"Så kører togene ikke i myldretiden?","en":"So the trains won't run in rush hour?"},{"foreign":"Mange stopper. Der bliver skiftebus fra endestationen.","en":"Many will stop. There will be a replacement bus from the terminus."},{"foreign":"Jeg tager bycyklen, selv om det regner på fortovet.","en":"I'll take the city bike, even if it rains on the sidewalk."},{"foreign":"Klogt. Eller tager du hjemmearbejde i morgen?","en":"Smart. Or are you working from home tomorrow?"},{"foreign":"Måske. Jeg skal snakke med lederen først, og tjekke budgettet til taxa.","en":"Maybe. I'll talk to the manager first, and check the budget for a taxi."},{"foreign":"Rundkørslen ved stationen bliver kaos. Tag letbanen hvis den kører.","en":"The roundabout by the station will be chaos. Take the light rail if it runs."},{"foreign":"Fint. Hold mig opdateret hvis afgangen bliver aflyst.","en":"Alright. Keep me posted if the departure is cancelled."}],"glosses":{"nyheden":"the news","strejke":"strike","metroen":"the subway","ruter":"routes","myldretiden":"rush hour","skiftebus":"replacement bus","endestationen":"the terminus","bycyklen":"the city bike","fortovet":"the sidewalk","hjemmearbejde":"remote work","lederen":"the manager","budgettet":"the budget","taxa":"taxi","rundkørslen":"the roundabout","letbanen":"the light rail","afgangen":"the departure","aflyst":"cancelled"}},{"id":"da-debat","title":"En kort debat","subtitle":"A short debate","trail":"double-black-diamond","categoryId":"da","sentences":[{"foreign":"Jeg synes offentlig transport er rigtig vigtig.","en":"I think public transport is really important."},{"foreign":"Hvorfor?","en":"Why?"},{"foreign":"Fordi ikke alle kan have bil i myldretiden, og parkeringsafgifterne er høje.","en":"Because not everyone can have a car in rush hour, and parking fees are high."},{"foreign":"Men busserne er altid fulde og forsinkede. Prisen på billetten stiger også.","en":"But the buses are always full and late. The ticket price is rising too."},{"foreign":"Hvis vi investerer mere i ruter, bliver det bedre. Se på bybudgettet.","en":"If we invest more in routes, it gets better. Look at the city budget."},{"foreign":"På lang sigt, måske. Lige nu er det dyrt. Rente og lån presser folk.","en":"In the long run, maybe. Right now it's expensive. Interest and loans put pressure on people."},{"foreign":"Sandt. Alligevel synes jeg det er det værd. Man kan overføre mere til kollektiv trafik.","en":"True. Even so, I think it's worth it. You can transfer more to public transport."},{"foreign":"Lad os læse mere før vi beslutter. Jeg tjekker min konto efter frokost.","en":"Let's read more before we decide. I'll check my account after lunch."},{"foreign":"Fint. Vi mødes ved hæveautomaten på stationen og snakker videre.","en":"Alright. We'll meet at the ATM at the station and talk more."}],"glosses":{"offentlig transport":"public transport","myldretiden":"rush hour","parkeringsafgifterne":"the parking fees","forsinkede":"delayed","billetten":"the ticket","ruter":"routes","bybudgettet":"the city budget","rente":"interest","lån":"loan","det værd":"worth it","overføre":"to transfer","konto":"account","frokost":"lunch","hæveautomaten":"the ATM"}},{"id":"da-planer","title":"Planer for sommeren","subtitle":"Summer plans","trail":"double-black-diamond","categoryId":"da","sentences":[{"foreign":"Hvad skal du lave i sommer?","en":"What are you going to do this summer?"},{"foreign":"Jeg vil rejse nogle uger, hvis det går. Har du planer?","en":"I want to travel a few weeks, if it works out. Do you have plans?"},{"foreign":"Måske til Skagen. Jeg booker tur-retur i appen i aften.","en":"Maybe to Skagen. I'm booking a round-trip in the app tonight."},{"foreign":"Har du pas klar? Bagagen skal indom check-in og paskontrol.","en":"Is your passport ready? The luggage has to go through check-in and passport control."},{"foreign":"Ja. Kun håndbagage. Gate og sæde står på boardingkortet efter sikkerhedskontrollen.","en":"Yes. Hand luggage only. Gate and seat are on the boarding pass after security."},{"foreign":"Ombordstigning starter tidligt. Efter landing henter du kufferten på bagagebåndet.","en":"Boarding starts early. After landing you pick up the suitcase on the baggage carousel."},{"foreign":"Jeg bliver og arbejder overtid. Opsparingen går til mit budget, og afdrag på lån.","en":"I'm staying and working overtime. The savings go into my budget, and loan installments."},{"foreign":"Praktisk. Mit fly kan blive forsinket. Ankomst er sent alligevel.","en":"Practical. My flight might be delayed. Arrival is late either way."},{"foreign":"Sig til når du lander. Terminalen er nem at finde.","en":"Let me know when you land. The terminal is easy to find."},{"foreign":"Gerne. Hold mig opdateret. Ha en god afgang!","en":"Will do. Keep me posted. Have a good departure!"}],"glosses":{"planer":"plans","booker":"am booking","tur-retur":"round-trip","pas":"passport","bagagen":"the luggage","check-in":"check-in","håndbagage":"hand luggage","gate":"gate","sæde":"seat","boardingkortet":"the boarding pass","sikkerhedskontrollen":"security","ombordstigning":"boarding","bagagebåndet":"the baggage carousel","overtid":"overtime","budget":"budget","afdrag":"installment","lån":"loan","forsinket":"delayed","ankomst":"arrival","lander":"land","terminalen":"the terminal","afgang":"departure","paskontrol":"passport control"}}]);
